import React , { useState }  from "react";
import logo from "./images/logo.png";
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import "./Home.css";
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';
import { useNavigate ,Link } from 'react-router-dom';

function Register(){
  const navigate = useNavigate();
    const [data,setData] = useState({
        email :"",
        name : "",
        surname : "",
        password :"",
        confirmPassword :"",
        contacts :"",
            
    });

    const [contract, setContract] = useState(false);
  

    const handleContract = () => {
      setContract(!contract);
    };



    const handleInputChange = (event) => {
        const { name, value } = event.target;
        setData((prevFormData) => ({
          ...prevFormData,
          [name]: value,
        }));
      };

      const handleSubmit = async (event) =>{
        event.preventDefault();




        if(data.email ==="" || data.name === ""){
          alert("enter email and Name");
        }
        else if (data.contacts ===""){
          alert("enter cellnumbers and location");
        }
        else if (data.password ==="" || data.confirmPassword ===""){
          alert("enter password and confirm password");
        }


        else{

          if(data.password !== data.confirmPassword){
            alert("Passwords do not match");
          }
          else{
            //run the code
            const formData = new FormData();
            formData.append('name', data.name);
            formData.append('surname', data.surname);
            formData.append('contacts', data.contacts);
            formData.append('email', data.email);
            formData.append('password', data.password);




            //submit to server
            try {
              const response = await fetch('http://localhost:5000/api/register', {
                method: 'POST',
                
                body: formData
              });
              const data = await response.json();
              if(response.ok){
                console.log('Data submitted successfully:', data);
                alert("you have been successfully registered on sociocash");
                navigate("/dashboard");
              }
              else if(!response.ok){
                alert("failed to register");
              }
           
              
            } catch (error) {
              console.error('Error submitting data:', error);
              alert(error);
            }

          }
        }
      }

      return(
        <div className="subs">
        <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home"><img
               src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
          /></Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
          <Nav.Link as={Link} to="/contact">Contacts</Nav.Link>
          <Nav.Link as={Link} to="/">Home</Nav.Link>
          <Nav.Link as={Link} to="/">Login</Nav.Link>
          </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

        <h1>Registration</h1>
        <Form onSubmit={handleSubmit}>
      <Form.Group className="mb-3 input" controlId="formBasicPassword">
        <Form.Label>Name</Form.Label>
        <Form.Control type="text" name="name" value={data.name} onChange={handleInputChange} placeholder="Enter your Name" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>

      <Form.Group className="mb-3 input" controlId="formBasicPassword">
        <Form.Label>Surname</Form.Label>
        <Form.Control type="text" name="surname" value={data.surname} onChange={handleInputChange} placeholder="Enter Surname" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>

      <Form.Group className="mb-3 input" controlId="formBasicPassword">
        <Form.Label>contacts</Form.Label>
        <Form.Control type="tel" name="contacts" value={data.contacts} onChange={handleInputChange} placeholder="Enter cellnumbers" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>


      <Form.Group className="mb-3 input" controlId="formBasicEmail">
        <Form.Label>Email address</Form.Label>
        <Form.Control type="email" name="email" value={data.email} onChange={handleInputChange} placeholder="Enter email" />
        <Form.Text className="text-muted">
          We'll never share your email with anyone else.
        </Form.Text>
      </Form.Group>

      <Form.Group className="mb-3 input" controlId="formBasicPassword">
        <Form.Label>Password</Form.Label>
        <Form.Control type="password" name="password" value={data.password} onChange={handleInputChange} placeholder="Password" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>

      <Form.Group className="mb-3 input" controlId="formBasicPassword">
        <Form.Label>ConfirmPassword</Form.Label>
        <Form.Control type="password" name="confirmPassword" value={data.confirmPassword} onChange={handleInputChange} placeholder="Confirm Password" />
      </Form.Group>
      <Form.Group className="mb-3" controlId="formBasicCheckbox">
      </Form.Group>
        <h3>Agreement to legal Terms</h3>
        <Form.Group className="mb-3 input" controlId="formBasicPassword"></Form.Group>
      <Form.Text className="text-muted">
          This is a legal contract that is binding smartLMS with our clients.

          We don't do refunds , so make sure to choose a subscription that you're confident in

        </Form.Text>
        <h3>Data Privacy</h3>
        <Form.Text className="text-muted">
          smartLMS agrees to not share information with third parties without your consent
        </Form.Text>
        <Form.Group/>

        <label>
        <input type="checkbox" checked={contract} onChange={handleContract} />
        I agree to the terms and conditions
      </label>


        <Button variant="danger"  type="submit" hidden={!contract}>
        Submit
      </Button>

        </Form>

        </div>
      );

}

export default Register;
